const GRID = 16;
const DEFAULT_SIZE = [96, 96];
const CONFIG_SIZE = [80, 80];
const CONFIGURABLE_MIN_WIDTH = 256;

const data = $input.first().json;
const {
  cleanedNodes, aiSubNodes, subNodeParents,
  outgoing, incoming, maxInputIndex, maxOutputIndex, workflowName
} = data;

// --- Helpers ---

const isTrigger = (node) => {
  const t = node.type || '';
  return t.includes('Trigger') || t.includes('trigger') || t.includes('webhook');
};

const getSimpleType = (fullType) => {
  if (!fullType) return 'unknown';
  const parts = fullType.split('.');
  return parts[parts.length - 1] || fullType;
};

const truncate = (str, max) =>
  !str ? '' : str.length <= max ? str : str.substring(0, max) + '...';

const safeGet = (obj, path, fallback) => {
  let cur = obj;
  for (const k of path.split('.')) {
    if (cur == null) return fallback;
    cur = cur[k];
  }
  return cur !== undefined ? cur : fallback;
};

// --- Node dimension calculator ---
// Based on n8n source: packages/frontend/editor-ui/src/app/utils/nodeViewUtils.ts

function getNodeDimensions(node) {
  const isSubNode = !!subNodeParents[node.id];
  const isAIParent = !!aiSubNodes[node.id];

  // Configuration nodes (sub-nodes) are circular 80x80
  if (isSubNode) {
    return { width: CONFIG_SIZE[0], height: CONFIG_SIZE[1] };
  }

  // Calculate height from actual input/output SLOT count (not connection count)
  const inputSlots = maxInputIndex[node.name] || 1;
  const outputSlots = maxOutputIndex[node.name] || 1;
  const maxHandles = Math.max(inputSlots, outputSlots, 1);
  const height = DEFAULT_SIZE[1] + Math.max(0, maxHandles - 2) * GRID * 2;

  // Configurable nodes (AI parents) are wider
  if (isAIParent) {
    const subCount = aiSubNodes[node.id].length;
    const portCount = Math.max(4, subCount);
    const calcWidth = 80 + GRID * ((portCount - 1) * 3);
    return { width: Math.max(CONFIGURABLE_MIN_WIDTH, calcWidth), height };
  }

  // Default nodes
  return { width: DEFAULT_SIZE[0], height };
}

// --- Context extractor (for AI prompt) ---

function extractContext(node) {
  const p = node.parameters || {};
  const type = getSimpleType(node.type);

  switch (type) {
    case 'httpRequest':
      return { description: `${p.method || 'GET'} request to ${truncate(p.url, 40) || 'URL'}` };
    case 'set':
      const fields = safeGet(p, 'assignments.assignments', [])
        .slice(0, 4).map(a => a.name).filter(Boolean);
      return { description: `Sets: ${fields.join(', ') || 'fields'}` };
    case 'if':
      return { description: 'Conditional branch' };
    case 'switch':
      return { description: 'Multi-way branch' };
    case 'code': {
      const first = (p.jsCode || '').split('\n')[0] || '';
      const hint = first.trim().startsWith('//')
        ? first.replace('//', '').trim()
        : 'Custom code';
      return { description: hint };
    }
    case 'filter':
      return { description: 'Filters items' };
    case 'merge':
      return { description: `Merge: ${p.mode || 'append'}` };
    case 'executeWorkflow':
      return { description: `Sub-workflow: ${truncate(safeGet(p, 'workflowId.cachedResultName', ''), 30) || 'workflow'}` };
    case 'postgres':
      return { description: p.operation === 'executeQuery' ? 'SQL query' : `Postgres ${p.operation || 'op'}` };
    case 'agent':
      return { description: 'AI Agent' };
    case 'chainLlm':
      return { description: 'LLM Chain' };
    case 'noOp':
      return { description: 'No operation (pass-through)' };
    case 'stopAndError':
      return { description: 'Stop with error' };
    case 'executionData':
      return { description: 'Set execution data' };
    default:
      if (isTrigger(node)) return { description: `${type} trigger` };
      return { description: `${type} node` };
  }
}

// --- Build enriched node list (excluding sub-nodes) ---

const nodes = [];

for (const node of cleanedNodes) {
  if (subNodeParents[node.id]) continue;

  const dims = getNodeDimensions(node);
  const subs = (aiSubNodes[node.id] || []).map(s => ({
    id: s.id,
    name: s.name,
    type: s.type,
    position: { x: s.position[0], y: s.position[1] },
    dimensions: getNodeDimensions({ id: s.id, type: s.type, name: s.name })
  }));

  nodes.push({
    id: node.id,
    name: node.name,
    simpleType: getSimpleType(node.type),
    position: { x: node.position[0], y: node.position[1] },
    dimensions: dims,
    context: extractContext(node),
    connectsTo: outgoing[node.name] || [],
    connectsFrom: incoming[node.name] || [],
    isEntryPoint: isTrigger(node) || (incoming[node.name] || []).length === 0,
    subNodes: subs
  });
}

return {
  json: {
    workflowName,
    nodeCount: nodes.length,
    nodes,
    aiSubNodes
  }
};

