parameters.jsCode:
const GRID = 16;
const MAIN_STICKY_WIDTH = 480;
const MAIN_STICKY_MIN_HEIGHT = 420;
const MAIN_STICKY_MAX_HEIGHT = 900;
const GAP_MAIN_TO_WORKFLOW = 80;  // 5 * GRID
const COLOR_WHITE = 7;

const data = $input.first().json;
const { groups, finalPositions, mainOverview, aiSubNodes } = data;
const parseData = $('Parse Nodes').first().json;
const workflowName = parseData.workflowName || 'Workflow overview';

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

function snapToGrid(val) {
  return Math.round(val / GRID) * GRID;
}

// --- Build main overview content ---

function formatMainOverview(overview, name) {
  let content = `## ${name}\n\n`;
  content += `### How it works\n\n${overview.howItWorks}\n\n`;
  content += `### Setup steps\n\n`;
  for (const step of (overview.setupSteps || [])) {
    content += `- ${step}\n`;
  }
  if (overview.customization?.trim()) {
    content += `\n### Customization\n\n${overview.customization}`;
  }
  return content;
}

function estimateContentHeight(content, width) {
  const charsPerLine = Math.floor(width / 8);
  let height = 60;
  for (const line of content.split('\n')) {
    if (line.startsWith('## ')) height += 40;
    else if (line.startsWith('### ')) height += 32;
    else if (line.trim() === '') height += 16;
    else if (line.startsWith('- ') || line.startsWith('* '))
      height += Math.ceil(line.length / charsPerLine) * 24;
    else height += Math.ceil(line.length / charsPerLine) * 22;
  }
  return height + 60;
}

// --- Find overall workflow bounds (from final positions of stickies) ---

let workflowMinX = Infinity;
let workflowMinY = Infinity;
let workflowMaxY = -Infinity;

for (const group of groups) {
  const s = group.sticky;
  workflowMinX = Math.min(workflowMinX, s.x);
  workflowMinY = Math.min(workflowMinY, s.y);
  workflowMaxY = Math.max(workflowMaxY, s.y + s.height);
}

if (workflowMinX === Infinity) {
  workflowMinX = 176;
  workflowMinY = 240;
  workflowMaxY = 500;
}

// --- Main overview sticky ---

const mainContent = formatMainOverview(mainOverview, workflowName);
const calcHeight = estimateContentHeight(mainContent, MAIN_STICKY_WIDTH);
const workflowSpan = workflowMaxY - workflowMinY;
const mainHeight = Math.max(
  MAIN_STICKY_MIN_HEIGHT,
  Math.min(MAIN_STICKY_MAX_HEIGHT, Math.max(calcHeight, workflowSpan))
);

const stickies = [];

stickies.push({
  parameters: {
    content: mainContent,
    width: MAIN_STICKY_WIDTH,
    height: snapToGrid(mainHeight)
  },
  type: 'n8n-nodes-base.stickyNote',
  typeVersion: 1,
  position: [
    snapToGrid(workflowMinX - MAIN_STICKY_WIDTH - GAP_MAIN_TO_WORKFLOW),
    snapToGrid(workflowMinY)
  ],
  id: uuid(),
  name: 'Sticky Note'
});

// --- Group stickies ---

for (let i = 0; i < groups.length; i++) {
  const group = groups[i];
  const s = group.sticky;

  let content = `## ${group.title}`;
  if (group.description?.trim()) {
    content += `\n\n${group.description}`;
  }

  stickies.push({
    parameters: {
      content,
      width: snapToGrid(s.width),
      height: snapToGrid(s.height),
      color: COLOR_WHITE
    },
    type: 'n8n-nodes-base.stickyNote',
    typeVersion: 1,
    position: [snapToGrid(s.x), snapToGrid(s.y)],
    id: uuid(),
    name: `Sticky Note${i + 1}`
  });
}

return {
  json: {
    stickies,
    finalPositions,
    aiSubNodes
  }
};

const workflow = $input.first().json.workflow;
const allNodes = workflow.nodes || [];
const connections = workflow.connections || {};

// 1. Remove existing sticky notes
const cleanedNodes = allNodes.filter(
  n => n.type !== 'n8n-nodes-base.stickyNote'
);

// 2. Build AI sub-node relationships
// Sub-nodes connect via ai_languageModel, ai_tool, ai_memory, ai_outputParser
const AI_CONNECTION_TYPES = new Set([
  'ai_languageModel', 'ai_tool', 'ai_memory', 'ai_outputParser'
]);

const nodesByName = {};
for (const node of cleanedNodes) {
  nodesByName[node.name] = node;
}

const aiSubNodes = {};      // parentId -> [{ id, name, type, position }]
const subNodeParents = {};  // subNodeId -> parentId

for (const [fromName, connDef] of Object.entries(connections)) {
  if (!connDef) continue;
  for (const [connType, outputs] of Object.entries(connDef)) {
    if (!AI_CONNECTION_TYPES.has(connType)) continue;
    for (const arr of (outputs || [])) {
      if (!Array.isArray(arr)) continue;
      for (const c of arr) {
        if (!c?.node) continue;
        const parentNode = nodesByName[c.node];
        const subNode = nodesByName[fromName];
        if (!parentNode || !subNode) continue;

        if (!aiSubNodes[parentNode.id]) aiSubNodes[parentNode.id] = [];
        aiSubNodes[parentNode.id].push({
          id: subNode.id,
          name: subNode.name,
          type: subNode.type,
          position: subNode.position
        });
        subNodeParents[subNode.id] = parentNode.id;
      }
    }
  }
}

// 3. Build main connection maps + count actual input/output SLOTS
const outgoing = {};  // nodeName -> [targetNodeNames]
const incoming = {};  // nodeName -> [sourceNodeNames]

// Track the highest input/output INDEX used per node (not just count of connections)
const maxInputIndex = {};   // nodeName -> highest input index seen
const maxOutputIndex = {};  // nodeName -> highest output index (= number of output arrays)

for (const [fromName, connDef] of Object.entries(connections)) {
  if (!connDef?.main) continue;

  // The number of output slots = length of the main array
  maxOutputIndex[fromName] = Math.max(
    maxOutputIndex[fromName] || 0,
    connDef.main.length
  );

  for (let outputIdx = 0; outputIdx < connDef.main.length; outputIdx++) {
    const outputArr = connDef.main[outputIdx];
    if (!Array.isArray(outputArr)) continue;
    for (const conn of outputArr) {
      if (!conn?.node) continue;

      if (!outgoing[fromName]) outgoing[fromName] = [];
      outgoing[fromName].push(conn.node);
      if (!incoming[conn.node]) incoming[conn.node] = [];
      incoming[conn.node].push(fromName);

      // Track the input index this connection targets
      const inputIdx = (conn.index ?? 0) + 1; // index is 0-based, we want count
      maxInputIndex[conn.node] = Math.max(
        maxInputIndex[conn.node] || 0,
        inputIdx
      );
    }
  }
}

return {
  json: {
    cleanedNodes,
    connections,
    aiSubNodes,
    subNodeParents,
    outgoing,
    incoming,
    maxInputIndex,
    maxOutputIndex,
    workflowName: workflow.name || 'Untitled workflow'
  }
};

const GRID = 16;
const PADDING_X = 48;          // 3 * GRID — side padding
const PADDING_BOTTOM = 64;     // 4 * GRID — matches n8n's STICKY_BOTTOM_PADDING
const MIN_PADDING_TOP = 80;    // minimum top padding even for short titles
const MIN_STICKY_WIDTH = 240;
const MIN_STICKY_HEIGHT = 180;

const aiOutput = $input.first().json.output || $input.first().json;
const parseData = $('Parse Nodes').first().json;

const { nodes: enrichedNodes, aiSubNodes } = parseData;

// Build lookup: nodeId -> enriched node data
const nodeById = {};
for (const n of enrichedNodes) {
  nodeById[n.id] = n;
  for (const sub of (n.subNodes || [])) {
    nodeById[sub.id] = sub;
  }
}

function snapToGrid(val) {
  return Math.round(val / GRID) * GRID;
}

// Calculate how much vertical space the sticky text will need
// so nodes don't overlap with the title/description
function estimateStickyTextHeight(title, description, stickyWidth) {
  const charsPerLine = Math.max(1, Math.floor(stickyWidth / 9));
  let height = 24; // top margin inside sticky

  // Title: "## 1. Title text"
  const titleText = `## ${title}`;
  const titleLines = Math.ceil(titleText.length / charsPerLine);
  height += titleLines * 36; // h2 line height

  // Description
  if (description && description.trim()) {
    height += 12; // gap between title and description
    const descLines = Math.ceil(description.length / charsPerLine);
    height += descLines * 22;
  }

  height += 20; // bottom margin before nodes start
  return Math.max(MIN_PADDING_TOP, height);
}

// For each group, compute the bounding box around all member nodes + sub-nodes
const groupBounds = [];

for (const group of aiOutput.groups) {
  const allNodeIds = [];

  for (const id of group.nodeIds) {
    allNodeIds.push(id);
    // Include sub-nodes of any AI parent in this group
    if (aiSubNodes[id]) {
      for (const sub of aiSubNodes[id]) {
        allNodeIds.push(sub.id);
      }
    }
  }

  let minX = Infinity, minY = Infinity;
  let maxX = -Infinity, maxY = -Infinity;

  for (const id of allNodeIds) {
    const node = nodeById[id];
    if (!node) continue;

    const x = node.position?.x ?? node.position?.[0] ?? 0;
    const y = node.position?.y ?? node.position?.[1] ?? 0;
    const w = node.dimensions?.width ?? 96;
    const h = node.dimensions?.height ?? 96;

    minX = Math.min(minX, x);
    minY = Math.min(minY, y);
    maxX = Math.max(maxX, x + w);
    maxY = Math.max(maxY, y + h);
  }

  if (minX === Infinity) continue; // empty group

  // First pass: estimate sticky width to calculate text height
  const rawWidth = Math.max(MIN_STICKY_WIDTH, maxX - minX + PADDING_X * 2);

  // Calculate dynamic top padding based on text content
  const textHeight = estimateStickyTextHeight(
    group.title || '',
    group.description || '',
    rawWidth
  );

  // Apply padding and snap
  const stickyX = snapToGrid(minX - PADDING_X);
  const stickyY = snapToGrid(minY - textHeight);
  const stickyWidth = snapToGrid(rawWidth);
  const stickyHeight = Math.max(
    MIN_STICKY_HEIGHT,
    snapToGrid(maxY - minY + textHeight + PADDING_BOTTOM)
  );

  groupBounds.push({
    groupId: group.groupId,
    title: group.title,
    description: group.description,
    nodeIds: group.nodeIds,
    sticky: {
      x: stickyX,
      y: stickyY,
      width: stickyWidth,
      height: stickyHeight
    },
    textHeight, // store for reference
    contentBounds: { minX, minY, maxX, maxY }
  });
}

return {
  json: {
    groupBounds,
    mainOverview: aiOutput.mainOverview,
    aiSubNodes
  }
};

const GRID = 16;
const GAP = 32;          // 2 * GRID — minimum gap between stickies
const MAX_ITERATIONS = 15;

const data = $input.first().json;
const parseData = $('Parse Nodes').first().json;

const { groupBounds, mainOverview, aiSubNodes } = data;
const { nodes: enrichedNodes } = parseData;

function snapToGrid(val) {
  return Math.round(val / GRID) * GRID;
}

// Build nodeId -> original position lookup
const nodePositions = {};
for (const n of enrichedNodes) {
  nodePositions[n.id] = { x: n.position.x, y: n.position.y };
  for (const sub of (n.subNodes || [])) {
    nodePositions[sub.id] = { x: sub.position.x, y: sub.position.y };
  }
}

// Working copy of group bounds and node positions
const groups = groupBounds.map(g => ({
  ...g,
  sticky: { ...g.sticky },
  shifted: { dx: 0, dy: 0 }
}));

// Detect overlap between two rectangles
function overlaps(a, b) {
  return !(
    a.x + a.width + GAP <= b.x ||
    b.x + b.width + GAP <= a.x ||
    a.y + a.height + GAP <= b.y ||
    b.y + b.height + GAP <= a.y
  );
}

// Calculate overlap amounts on each axis
function overlapAmount(a, b) {
  const overX = Math.min(a.x + a.width, b.x + b.width) - Math.max(a.x, b.x);
  const overY = Math.min(a.y + a.height, b.y + b.height) - Math.max(a.y, b.y);
  return { x: Math.max(0, overX), y: Math.max(0, overY) };
}

// Resolve collisions iteratively
// Groups ordered by index (execution flow) — lower index = higher priority (stays put)
let iterations = 0;
let hasOverlap = true;

while (hasOverlap && iterations < MAX_ITERATIONS) {
  hasOverlap = false;
  iterations++;

  for (let i = 0; i < groups.length; i++) {
    for (let j = i + 1; j < groups.length; j++) {
      const a = groups[i].sticky;
      const b = groups[j].sticky;

      if (!overlaps(a, b)) continue;
      hasOverlap = true;

      const overlap = overlapAmount(a, b);

      // Determine shift direction: push along axis of LEAST overlap
      // (minimum displacement to resolve)
      let dx = 0, dy = 0;

      if (overlap.x <= overlap.y) {
        // Push horizontally
        dx = overlap.x + GAP;
        // Push right if b is to the right of a, otherwise push left
        if (b.x + b.width / 2 < a.x + a.width / 2) {
          dx = -dx;
        }
      } else {
        // Push vertically
        dy = overlap.y + GAP;
        if (b.y + b.height / 2 < a.y + a.height / 2) {
          dy = -dy;
        }
      }

      dx = snapToGrid(dx);
      dy = snapToGrid(dy);

      // Shift group j (lower priority)
      groups[j].sticky.x += dx;
      groups[j].sticky.y += dy;
      groups[j].shifted.dx += dx;
      groups[j].shifted.dy += dy;
    }
  }
}

// Apply accumulated shifts to node positions
const finalPositions = { ...nodePositions };

for (const group of groups) {
  if (group.shifted.dx === 0 && group.shifted.dy === 0) continue;

  const allNodeIds = [...group.nodeIds];
  for (const id of group.nodeIds) {
    if (aiSubNodes[id]) {
      for (const sub of aiSubNodes[id]) {
        allNodeIds.push(sub.id);
      }
    }
  }

  for (const id of allNodeIds) {
    if (!finalPositions[id]) continue;
    finalPositions[id] = {
      x: snapToGrid(finalPositions[id].x + group.shifted.dx),
      y: snapToGrid(finalPositions[id].y + group.shifted.dy)
    };
  }
}

return {
  json: {
    groups,
    finalPositions,
    mainOverview,
    aiSubNodes,
    totalShifted: groups.filter(g => g.shifted.dx !== 0 || g.shifted.dy !== 0).length,
    iterations
  }
};

const stickyData = $input.first().json;
const originalWorkflow = $('Set Workflow Variables').first().json.workflow;
const { stickies, finalPositions, aiSubNodes } = stickyData;

// Deep copy workflow
const workflow = JSON.parse(JSON.stringify(originalWorkflow));

// Remove old stickies
const nodesWithoutStickies = workflow.nodes.filter(
  n => n.type !== 'n8n-nodes-base.stickyNote'
);

// Update positions for nodes that were shifted during collision resolution
for (const node of nodesWithoutStickies) {
  const pos = finalPositions[node.id];
  if (pos) {
    node.position = [pos.x, pos.y];
  }
}

// Combine: stickies first (so they render behind nodes), then all nodes
workflow.nodes = [...stickies, ...nodesWithoutStickies];

return {
  json: {
    workflow,
    workflowJson: JSON.stringify(workflow, null, 2),
    message: 'Stickies generated — original layout preserved, collisions resolved'
  }
};

const data = $input.first().json;
const workflow = data.bestWorkflow;

return {
  json: {
    workflow,
    totalPasses: data.collisionIteration,
    finalCollisions: data.bestCollisionCount,
    message: data.bestCollisionCount === 0
      ? `Clean — no collisions (resolved in ${data.collisionIteration} pass${data.collisionIteration > 1 ? 'es' : ''})`
      : `Best result after ${data.collisionIteration} passes: ${data.bestCollisionCount} remaining collision${data.bestCollisionCount > 1 ? 's' : ''}`
  }
};

const GRID = 16;
const GAP = 32;            // minimum gap between stickies
const NODE_GAP = 16;       // minimum gap between sticky edge and foreign node
const MAX_FIX_PASSES = 10;

const input = $input.first().json;
const workflow = JSON.parse(JSON.stringify(input.workflow));
const iteration = (input.collisionIteration || 0) + 1;

function snapToGrid(val) {
  return Math.round(val / GRID) * GRID;
}

// Separate stickies and regular nodes
const stickies = [];
const regularNodes = [];

for (const node of workflow.nodes) {
  if (node.type === 'n8n-nodes-base.stickyNote') {
    stickies.push(node);
  } else {
    regularNodes.push(node);
  }
}

// Get sticky bounds
function stickyRect(s) {
  return {
    id: s.id,
    x: s.position[0],
    y: s.position[1],
    w: s.parameters.width || 240,
    h: s.parameters.height || 180,
    right() { return this.x + this.w; },
    bottom() { return this.y + this.h; }
  };
}

// Get node bounds (assume 96x96 default — we don't have dimensions here,
// but this is a safety net, not precision pass)
function nodeRect(n) {
  return {
    id: n.id,
    x: n.position[0],
    y: n.position[1],
    w: 96,
    h: 96,
    right() { return this.x + this.w; },
    bottom() { return this.y + this.h; }
  };
}

// Check if two rects overlap with a gap
function rectsOverlap(a, b, gap) {
  return !(
    a.right() + gap <= b.x ||
    b.right() + gap <= a.x ||
    a.bottom() + gap <= b.y ||
    b.bottom() + gap <= a.y
  );
}

// Determine which nodes are "inside" each sticky
// A node is inside a sticky if it's fully contained within the sticky bounds
function nodeInsideSticky(nodeR, stickyR) {
  return (
    nodeR.x >= stickyR.x &&
    nodeR.y >= stickyR.y &&
    nodeR.right() <= stickyR.right() &&
    nodeR.bottom() <= stickyR.bottom()
  );
}

// Build ownership: which regular nodes belong to which sticky
const stickyOwnership = {}; // stickyId -> Set of nodeIds

for (const s of stickies) {
  const sr = stickyRect(s);
  stickyOwnership[s.id] = new Set();
  for (const n of regularNodes) {
    const nr = nodeRect(n);
    if (nodeInsideSticky(nr, sr)) {
      stickyOwnership[s.id].add(n.id);
    }
  }
}

let collisionsFound = 0;

// --- Pass 1: Sticky-to-sticky collisions ---
// Main overview sticky (index 0, no color = yellow) gets highest priority
// Then ordered by position (left-to-right, top-to-bottom)

const sortedStickies = [...stickies].sort((a, b) => {
  // Main overview (no color parameter) gets priority
  const aIsMain = !a.parameters.color;
  const bIsMain = !b.parameters.color;
  if (aIsMain && !bIsMain) return -1;
  if (!aIsMain && bIsMain) return 1;
  // Otherwise sort by x position, then y
  if (a.position[0] !== b.position[0]) return a.position[0] - b.position[0];
  return a.position[1] - b.position[1];
});

for (let pass = 0; pass < MAX_FIX_PASSES; pass++) {
  let fixedAny = false;

  for (let i = 0; i < sortedStickies.length; i++) {
    for (let j = i + 1; j < sortedStickies.length; j++) {
      const a = stickyRect(sortedStickies[i]);
      const b = stickyRect(sortedStickies[j]);

      if (!rectsOverlap(a, b, GAP)) continue;

      collisionsFound++;
      fixedAny = true;

      // Calculate overlap on each axis
      const overX = Math.min(a.right(), b.right()) - Math.max(a.x, b.x) + GAP;
      const overY = Math.min(a.bottom(), b.bottom()) - Math.max(a.y, b.y) + GAP;

      let dx = 0, dy = 0;

      // Push along axis of least overlap
      if (overX <= overY) {
        dx = overX;
        if (b.x + b.w / 2 < a.x + a.w / 2) dx = -dx;
      } else {
        dy = overY;
        if (b.y + b.h / 2 < a.y + a.h / 2) dy = -dy;
      }

      dx = snapToGrid(dx);
      dy = snapToGrid(dy);

      // Shift sticky j
      sortedStickies[j].position[0] += dx;
      sortedStickies[j].position[1] += dy;

      // Shift all nodes owned by sticky j
      const ownedIds = stickyOwnership[sortedStickies[j].id] || new Set();
      for (const node of regularNodes) {
        if (ownedIds.has(node.id)) {
          node.position[0] = snapToGrid(node.position[0] + dx);
          node.position[1] = snapToGrid(node.position[1] + dy);
        }
      }
    }
  }

  if (!fixedAny) break;
}

// --- Pass 2: Check for foreign nodes overlapping stickies ---
// A "foreign" node is one that overlaps a sticky it doesn't belong to

for (let pass = 0; pass < MAX_FIX_PASSES; pass++) {
  let fixedAny = false;

  for (const s of stickies) {
    const sr = stickyRect(s);
    const owned = stickyOwnership[s.id] || new Set();

    for (const n of regularNodes) {
      if (owned.has(n.id)) continue; // skip nodes that belong to this sticky
      const nr = nodeRect(n);

      if (!rectsOverlap(sr, nr, NODE_GAP)) continue;

      // Foreign node overlaps this sticky — expand the sticky to avoid it
      // OR shift the sticky. Expanding is safer (doesn't cascade).
      // We'll shrink the sticky edge away from the node.

      // Actually, the safest fix: grow the sticky so its edge clears the node,
      // but only if the node is just barely clipping. If major overlap,
      // we shift the sticky instead.

      const overlapArea = (
        Math.max(0, Math.min(sr.right(), nr.right()) - Math.max(sr.x, nr.x)) *
        Math.max(0, Math.min(sr.bottom(), nr.bottom()) - Math.max(sr.y, nr.y))
      );

      // If overlap is small relative to sticky, just note it
      // The main sticky-to-sticky resolution should have handled most cases
      if (overlapArea > 0) {
        collisionsFound++;
        fixedAny = true;

        // Determine which edge of the sticky the node is closest to
        const distLeft = Math.abs(nr.right() - sr.x);
        const distRight = Math.abs(nr.x - sr.right());
        const distTop = Math.abs(nr.bottom() - sr.y);
        const distBottom = Math.abs(nr.y - sr.bottom());
        const minDist = Math.min(distLeft, distRight, distTop, distBottom);

        // Pull the sticky edge back + shift owned nodes
        const shift = NODE_GAP + GRID;
        let sdx = 0, sdy = 0;

        if (minDist === distRight) {
          // Node is near right edge — shrink width
          s.parameters.width = snapToGrid(Math.max(240, sr.x + sr.w - nr.x - shift));
        } else if (minDist === distBottom) {
          // Node is near bottom edge — shrink height
          s.parameters.height = snapToGrid(Math.max(180, sr.y + sr.h - nr.y - shift));
        } else if (minDist === distLeft) {
          // Node is near left edge — shift sticky right
          sdx = snapToGrid(nr.right() + shift - sr.x);
          s.position[0] += sdx;
          s.parameters.width = snapToGrid(Math.max(240, sr.w - sdx));
        } else {
          // Node is near top edge — shift sticky down
          sdy = snapToGrid(nr.bottom() + shift - sr.y);
          s.position[1] += sdy;
          s.parameters.height = snapToGrid(Math.max(180, sr.h - sdy));
        }
      }
    }
  }

  if (!fixedAny) break;
}

// Reassemble workflow
workflow.nodes = [...stickies, ...regularNodes];

return {
  json: {
    workflow,
    workflowJson: JSON.stringify(workflow, null, 2),
    collisionsFound,
    collisionIteration: iteration,
    hasCollisions: collisionsFound > 0 && iteration < 5
  }
};

const max_retries = $('Set Workflow Variables').first().json.MAX_RETRIES;
const state = $getWorkflowStaticData('global');
const executionId = $execution.id;

if (state._executionId !== executionId) {
  state._executionId = executionId;
  state.loopCount = 0;
  state.bestCollisionCount = Infinity;
  state.bestWorkflow = null;
  state.bestIteration = 0;
  state.originalWorkflow = $('Set Workflow Variables').first().json.workflow;
}

const input = $input.first().json;
const currentCollisions = input.collisionsFound;
const currentWorkflow = input.workflow;

state.loopCount += 1;

if (currentCollisions < state.bestCollisionCount) {
  state.bestCollisionCount = currentCollisions;
  state.bestWorkflow = JSON.parse(JSON.stringify(currentWorkflow));
  state.bestIteration = state.loopCount;
}

const shouldRetry = currentCollisions > 0 && state.loopCount < max_retries;

if (shouldRetry) {
  return {
    json: {
      workflow: state.originalWorkflow,
      loopCount: state.loopCount,
      lastCollisions: currentCollisions,
      bestSoFar: state.bestCollisionCount,
      _loopRetry: true
    }
  };
} else {
  return {
    json: {
      bestWorkflow: state.bestWorkflow,
      bestCollisionCount: state.bestCollisionCount,
      bestIteration: state.bestIteration,
      totalPasses: state.loopCount,
      collisionIteration: state.loopCount,
      _loopRetry: false
    }
  };
}

// Get the workflow JSON from the first input item
const workflow = $input.first().json.workflow;
const allNodes = workflow.nodes || [];
const connections = workflow.connections || {};

// Helper to detect sticky notes (we'll skip these)
const isSticky = (node) => node.type === 'n8n-nodes-base.stickyNote';

// Helper to extract simplified type name
const getSimpleType = (fullType) => {
  if (!fullType) return 'unknown';
  const parts = fullType.split('.');
  return parts[parts.length - 1] || fullType;
};

// Helper to safely get nested value
const safeGet = (obj, path, defaultVal = undefined) => {
  const keys = path.split('.');
  let current = obj;
  for (const key of keys) {
    if (current === null || current === undefined) return defaultVal;
    current = current[key];
  }
  return current !== undefined ? current : defaultVal;
};

// Helper to truncate string
const truncate = (str, maxLen) => {
  if (!str) return '';
  if (str.length <= maxLen) return str;
  return str.substring(0, maxLen) + '...';
};

// Build connection maps
const outgoingConnections = {}; // nodeName -> [targetNames]
const incomingConnections = {}; // nodeName -> [sourceNames]

for (const [fromName, connDef] of Object.entries(connections)) {
  if (!connDef) continue;

  // Process main connections
  const mains = connDef.main || [];
  for (const outputArr of mains) {
    if (!Array.isArray(outputArr)) continue;
    for (const conn of outputArr) {
      if (!conn || !conn.node) continue;

      // Outgoing from source
      if (!outgoingConnections[fromName]) outgoingConnections[fromName] = [];
      outgoingConnections[fromName].push(conn.node);

      // Incoming to target
      if (!incomingConnections[conn.node]) incomingConnections[conn.node] = [];
      incomingConnections[conn.node].push(fromName);
    }
  }

  // Process AI connections (ai_languageModel, ai_tool, etc.)
  for (const [key, value] of Object.entries(connDef)) {
    if (key === 'main') continue;
    if (!Array.isArray(value)) continue;

    for (const outputArr of value) {
      if (!Array.isArray(outputArr)) continue;
      for (const conn of outputArr) {
        if (!conn || !conn.node) continue;

        if (!outgoingConnections[fromName]) outgoingConnections[fromName] = [];
        outgoingConnections[fromName].push(conn.node);

        if (!incomingConnections[conn.node]) incomingConnections[conn.node] = [];
        incomingConnections[conn.node].push(fromName);
      }
    }
  }
}

// Extract context based on node type
function extractContext(node) {
  const p = node.parameters || {};
  const type = getSimpleType(node.type);

  switch (type) {
    case 'httpRequest':
      return {
        method: p.method || 'GET',
        url: truncate(p.url, 80),
        authentication: p.authentication || 'none',
        description: `${p.method || 'GET'} request to ${truncate(p.url, 50) || 'URL'}`
      };

    case 'set':
      const assignments = safeGet(p, 'assignments.assignments', []);
      const fieldNames = assignments.slice(0, 5).map(a => a.name).filter(Boolean);
      return {
        fields: fieldNames,
        fieldCount: assignments.length,
        description: `Sets fields: ${fieldNames.join(', ') || 'various'}`
      };

    case 'if':
      const conditions = safeGet(p, 'conditions.conditions', []);
      const conditionCount = conditions.length;
      const firstCondition = conditions[0];
      let conditionDesc = 'condition';
      if (firstCondition) {
        const left = String(firstCondition.leftValue || '').substring(0, 30);
        const op = safeGet(firstCondition, 'operator.operation', 'equals');
        conditionDesc = `${left} ${op}`;
      }
      return {
        conditionCount,
        description: `Checks ${conditionDesc}`
      };

    case 'switch':
      const rules = safeGet(p, 'rules.rules', []);
      return {
        ruleCount: rules.length,
        description: `Routes based on ${rules.length} rules`
      };

    case 'code':
      const jsCode = p.jsCode || p.code || '';
      const firstLine = jsCode.split('\n')[0] || '';
      const isComment = firstLine.trim().startsWith('//');
      return {
        language: p.language || 'javascript',
        mode: p.mode || 'runOnceForAllItems',
        hint: isComment ? firstLine.replace('//', '').trim() : truncate(firstLine, 50),
        description: isComment ? firstLine.replace('//', '').trim() : 'Custom code'
      };

    case 'filter':
      const filterConditions = safeGet(p, 'conditions.conditions', []);
      return {
        conditionCount: filterConditions.length,
        description: `Filters items based on ${filterConditions.length} condition(s)`
      };

    case 'googleSheets':
      return {
        operation: p.operation || 'read',
        sheetName: safeGet(p, 'sheetName.cachedResultName', 'Sheet'),
        documentName: safeGet(p, 'documentId.cachedResultName', 'Document'),
        description: `${p.operation || 'Read'} ${safeGet(p, 'sheetName.cachedResultName', 'sheet')}`
      };

    case 'slack':
      return {
        resource: p.resource || 'message',
        operation: p.operation || 'post',
        channel: safeGet(p, 'channelId.cachedResultName', 'channel'),
        description: `${p.operation || 'Post'} ${p.resource || 'message'} to Slack`
      };

    case 'gmail':
    case 'gmailTrigger':
      return {
        operation: p.operation || 'send',
        description: type === 'gmailTrigger' ? 'Triggered by Gmail' : `${p.operation || 'Send'} email via Gmail`
      };

    case 'webhook':
      return {
        httpMethod: p.httpMethod || 'GET',
        path: p.path || '/',
        description: `Webhook endpoint: ${p.httpMethod || 'GET'} ${p.path || '/'}`
      };

    case 'scheduleTrigger':
      const rule = safeGet(p, 'rule.interval', []);
      return {
        rule: rule,
        description: 'Runs on schedule'
      };

    case 'manualTrigger':
      return {
        description: 'Manual execution trigger'
      };

    case 'wait':
      return {
        resumeMode: p.resume || 'timeInterval',
        amount: p.amount,
        unit: p.unit,
        description: p.amount ? `Wait ${p.amount} ${p.unit || 'seconds'}` : 'Wait for event'
      };

    case 'splitInBatches':
      return {
        batchSize: p.batchSize || 10,
        description: `Process in batches of ${p.batchSize || 10}`
      };

    case 'splitOut':
      return {
        fieldToSplit: p.fieldToSplitOut || 'items',
        description: `Split out ${p.fieldToSplitOut || 'items'}`
      };

    case 'merge':
      return {
        mode: p.mode || 'append',
        description: `Merge data: ${p.mode || 'append'}`
      };

    case 'removeDuplicates':
      return {
        compareField: p.fieldsToCompare || 'all',
        description: `Remove duplicates by ${p.fieldsToCompare || 'all fields'}`
      };

    case 'sort':
      const sortField = safeGet(p, 'sortFieldsUi.sortField[0].fieldName', 'field');
      return {
        sortBy: sortField,
        description: `Sort by ${sortField}`
      };

    case 'limit':
      return {
        maxItems: p.maxItems || 10,
        description: `Limit to ${p.maxItems || 10} items`
      };

    case 'agent':
      return {
        promptType: p.promptType,
        description: 'AI Agent node'
      };

    case 'lmChatOpenAi':
      return {
        model: safeGet(p, 'model.value', 'gpt-4'),
        description: `OpenAI ${safeGet(p, 'model.value', 'model')}`
      };

    case 'lmChatAnthropic':
      return {
        model: safeGet(p, 'model.value', 'claude'),
        description: `Anthropic ${safeGet(p, 'model.value', 'model')}`
      };

    default:
      return {
        description: `${type} node`
      };
  }
}

// Check if node has expression references to other nodes
function findExpressionReferences(node) {
  const refs = [];
  const jsonStr = JSON.stringify(node.parameters || {});

  // Find $('Node Name') patterns
  const regex = /\$\(['"]([^'"]+)['"]\)/g;
  let match;
  while ((match = regex.exec(jsonStr)) !== null) {
    refs.push(match[1]);
  }

  return refs;
}

// Process all nodes
const nodesForRenaming = [];
const existingNames = [];

for (const node of allNodes) {
  // Skip sticky notes
  if (isSticky(node)) continue;

  existingNames.push(node.name);

  const context = extractContext(node);
  const expressionRefs = findExpressionReferences(node);

  nodesForRenaming.push({
    id: node.id,
    currentName: node.name,
    type: node.type,
    simpleType: getSimpleType(node.type),
    context,
    incomingFrom: [...new Set(incomingConnections[node.name] || [])],
    outgoingTo: [...new Set(outgoingConnections[node.name] || [])],
    hasExpressionRefs: expressionRefs.length > 0,
    expressionRefs
  });
}

return {
  json: {
    workflowName: workflow.name || 'Untitled workflow',
    nodeCount: nodesForRenaming.length,
    nodes: nodesForRenaming,
    existingNames
  }
};

