// Get inputs
const aiOutput = $input.first().json.output || $input.first().json;
const originalWorkflow = $('Pick Best Result').first().json.workflow;

// Validate AI output
if (!aiOutput.renames || !Array.isArray(aiOutput.renames)) {
  throw new Error('Invalid AI output: missing renames array');
}

// Deep clone the workflow to avoid modifying original
const workflow = JSON.parse(JSON.stringify(originalWorkflow));

// Build rename maps
const idToNewName = {};      // id -> newName
const oldToNewName = {};     // oldName -> newName
const usedNames = new Set(); // Track used names to ensure uniqueness

// First pass: collect all renames and ensure uniqueness
for (const rename of aiOutput.renames) {
  let newName = rename.newName;

  // Ensure uniqueness by adding suffix if needed
  let baseName = newName;
  let counter = 1;
  while (usedNames.has(newName)) {
    newName = `${baseName} ${counter}`;
    counter++;
  }

  usedNames.add(newName);
  idToNewName[rename.id] = newName;
  oldToNewName[rename.currentName] = newName;
}

// Helper to escape special regex characters
function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Helper to update expression references in a string
function updateExpressionRefs(str, oldToNew) {
  if (typeof str !== 'string') return str;

  let result = str;

  // Update $('Old Name') to $('New Name')
  for (const [oldName, newName] of Object.entries(oldToNew)) {
    // Handle both single and double quotes
    const patterns = [
      new RegExp(`\\$\\('${escapeRegex(oldName)}'\\)`, 'g'),
      new RegExp(`\\$\\("${escapeRegex(oldName)}"\\)`, 'g')
    ];

    for (const pattern of patterns) {
      result = result.replace(pattern, `$('${newName}')`);
    }
  }

  return result;
}

// Recursively update expression references in an object
function updateExpressionsInObject(obj, oldToNew) {
  if (obj === null || obj === undefined) return obj;

  if (typeof obj === 'string') {
    return updateExpressionRefs(obj, oldToNew);
  }

  if (Array.isArray(obj)) {
    return obj.map(item => updateExpressionsInObject(item, oldToNew));
  }

  if (typeof obj === 'object') {
    const result = {};
    for (const [key, value] of Object.entries(obj)) {
      result[key] = updateExpressionsInObject(value, oldToNew);
    }
    return result;
  }

  return obj;
}

// ---------- STEP 1: Rename nodes ----------
for (const node of workflow.nodes) {
  // Skip sticky notes
  if (node.type === 'n8n-nodes-base.stickyNote') continue;

  const newName = idToNewName[node.id];
  if (newName) {
    node.name = newName;
  }

  // Update expression references in node parameters
  if (node.parameters) {
    node.parameters = updateExpressionsInObject(node.parameters, oldToNewName);
  }
}

// ---------- STEP 2: Update connections ----------
// Connections are keyed by node name and reference target nodes by name
const newConnections = {};

for (const [oldSourceName, connDef] of Object.entries(workflow.connections || {})) {
  // Get the new source name (or keep old if not renamed)
  const newSourceName = oldToNewName[oldSourceName] || oldSourceName;

  // Deep clone the connection definition
  const newConnDef = JSON.parse(JSON.stringify(connDef));

  // Update all target node references
  for (const [connType, outputs] of Object.entries(newConnDef)) {
    if (!Array.isArray(outputs)) continue;

    for (const outputArr of outputs) {
      if (!Array.isArray(outputArr)) continue;

      for (const conn of outputArr) {
        if (conn && conn.node) {
          // Update target node name
          const newTargetName = oldToNewName[conn.node] || conn.node;
          conn.node = newTargetName;
        }
      }
    }
  }

  newConnections[newSourceName] = newConnDef;
}

workflow.connections = newConnections;

// ---------- STEP 3: Update pinData keys if present ----------
if (workflow.pinData) {
  const newPinData = {};

  for (const [oldName, data] of Object.entries(workflow.pinData)) {
    const newName = oldToNewName[oldName] || oldName;
    newPinData[newName] = data;
  }

  workflow.pinData = newPinData;
}

// ---------- STEP 4: Build rename report ----------
const renameReport = aiOutput.renames.map(r => ({
  id: r.id,
  oldName: r.currentName,
  newName: idToNewName[r.id]
}));

return {
  json: {
    workflow,
    renameReport,
    totalRenamed: renameReport.length
  }
};

// Get the renamed workflow from previous node
const data = $input.first().json;
const workflow = data.workflow;
const renameReport = data.renameReport;

// Return both the workflow JSON string and the rename report
return {
  json: {
    // The workflow object for any downstream processing
    workflow: workflow,

    // Summary of what was renamed
    renameReport: renameReport
  }
};

